14	#[rocket::get("/?<page>&<per_page>&<search>&<sort_by>&<sort_order>")]
15	pub async fn list_users(
16	    user: AuthenticatedUser,
17	    perm_cache: &State<PermissionCache>,
18	    user_service: &State<UserService>,
19	    page: Option<i64>,
20	    per_page: Option<i64>,
21	    search: Option<String>,
22	    sort_by: Option<String>,
23	    sort_order: Option<String>,
24	) -> Result<Json<PaginatedResponse<UserRow>>, AppError> {
25	    guards::require_permission(perm_cache, &user.user_id, auth_policy::api::USERS_READ).await?;
26	    guards::require_data_scope(perm_cache, &user.user_id, &user.org_id, None, None, "read").await?;
27	    let params = PaginationParams { page, per_page, search, sort_by, sort_order };
28	    let result = user_service.list_users(&user.org_id, &params).await?;
29	    Ok(Json(result))
30	}
