1	use parking_lot::RwLock;
2	use sqlx::MySqlPool;
3	use std::collections::{HashMap, HashSet};
4	use std::sync::Arc;
5	use std::time::{Duration, Instant};
6	
7	/// In-process permission cache with version-based invalidation.
8	///
9	/// Design:
10	/// - Caches user -> {permissions, data_scopes} mappings
11	/// - Checks `permission_version` table on every access if entry is older than TTL
12	/// - If the global version has changed, the entire cache is invalidated
13	/// - TTL is 30 seconds max, ensuring permission changes take effect within 30s
14	/// - Thread-safe via parking_lot RwLock for low-contention reads
15	#[derive(Clone)]
16	pub struct PermissionCache {
17	    inner: Arc<RwLock<CacheInner>>,
18	    pool: MySqlPool,
19	    ttl: Duration,
20	}
21	
22	struct CacheInner {
23	    entries: HashMap<String, CachedUserPermissions>,
24	    known_version: u64,
25	    last_version_check: Instant,
26	}
27	
28	#[derive(Debug, Clone)]
29	pub struct CachedUserPermissions {
30	    pub user_id: String,
31	    pub permission_codes: HashSet<String>,
32	    pub data_scopes: Vec<DataScope>,
33	    pub role_names: HashSet<String>,
34	    pub cached_at: Instant,
35	}
36	
37	#[derive(Debug, Clone, serde::Serialize)]
38	pub struct DataScope {
39	    pub org_id: String,
40	    pub department_id: Option<String>,
41	    pub project_id: Option<String>,
42	    pub access_level: String,
43	}
44	
45	impl PermissionCache {
46	    pub fn new(pool: MySqlPool, ttl_seconds: u64) -> Self {
47	        let ttl = Duration::from_secs(ttl_seconds.min(30)); // Enforce max 30s
48	        Self {
49	            inner: Arc::new(RwLock::new(CacheInner {
50	                entries: HashMap::new(),
51	                known_version: 0,
52	                last_version_check: Instant::now() - ttl - Duration::from_secs(1), // Force first check
53	            })),
54	            pool,
55	            ttl,
56	        }
57	    }
58	
59	    /// Get cached permissions for a user, loading from DB if stale or missing.
60	    pub async fn get_permissions(&self, user_id: &str) -> Result<CachedUserPermissions, sqlx::Error> {
61	        // Check if version has changed (every TTL interval)
62	        self.check_version().await?;
63	
64	        // Try cache read
65	        {
66	            let cache = self.inner.read();
67	            if let Some(entry) = cache.entries.get(user_id) {
68	                if entry.cached_at.elapsed() < self.ttl {
69	                    return Ok(entry.clone());
70	                }
71	            }
72	        }
73	
74	        // Cache miss or stale: load from DB
75	        let perms = self.load_user_permissions(user_id).await?;
76	
77	        // Store in cache
78	        {
79	            let mut cache = self.inner.write();
80	            cache.entries.insert(user_id.to_string(), perms.clone());
81	        }
82	
83	        Ok(perms)
84	    }
85	
86	    /// Force invalidation of the entire cache. Called when permissions change.
87	    pub async fn invalidate(&self) -> Result<(), sqlx::Error> {
88	        // Increment the global version counter
89	        sqlx::query("UPDATE permission_version SET version = version + 1 WHERE id = 1")
90	            .execute(&self.pool)
91	            .await?;
92	
93	        // Clear local cache
94	        {
95	            let mut cache = self.inner.write();
96	            cache.entries.clear();
97	            cache.known_version = 0; // Force re-check
98	        }
99	
100	        tracing::info!("Permission cache invalidated");
101	        Ok(())
102	    }
103	
104	    /// Invalidate a single user's cached permissions.
105	    pub fn invalidate_user(&self, user_id: &str) {
106	        let mut cache = self.inner.write();
107	        cache.entries.remove(user_id);
108	    }
109	
110	    /// Check the global version counter. If it changed, clear the cache.
111	    async fn check_version(&self) -> Result<(), sqlx::Error> {
112	        let should_check = {
113	            let cache = self.inner.read();
114	            cache.last_version_check.elapsed() >= self.ttl
115	        };
116	
117	        if !should_check {
118	            return Ok(());
119	        }
120	
121	        let row: (u64,) = sqlx::query_as("SELECT version FROM permission_version WHERE id = 1")
122	            .fetch_one(&self.pool)
123	            .await?;
124	
125	        let mut cache = self.inner.write();
126	        cache.last_version_check = Instant::now();
127	
128	        if row.0 != cache.known_version {
129	            tracing::debug!(
130	                old_version = cache.known_version,
131	                new_version = row.0,
132	                "Permission version changed, clearing cache"
133	            );
134	            cache.entries.clear();
135	            cache.known_version = row.0;
136	        }
137	
138	        Ok(())
139	    }
140	
141	    /// Load a user's full permission set from the database.
142	    async fn load_user_permissions(&self, user_id: &str) -> Result<CachedUserPermissions, sqlx::Error> {
143	        // Load role names
144	        let role_rows: Vec<(String,)> = sqlx::query_as(
145	            "SELECT r.name FROM roles r
146	             INNER JOIN user_roles ur ON ur.role_id = r.id
147	             WHERE ur.user_id = ?"
148	        )
149	        .bind(user_id)
150	        .fetch_all(&self.pool)
151	        .await?;
152	
153	        let role_names: HashSet<String> = role_rows.into_iter().map(|r| r.0).collect();
154	
155	        // Load permission codes through role -> role_permissions -> permissions
156	        let perm_rows: Vec<(String,)> = sqlx::query_as(
157	            "SELECT DISTINCT p.code FROM permissions p
158	             INNER JOIN role_permissions rp ON rp.permission_id = p.id
159	             INNER JOIN user_roles ur ON ur.role_id = rp.role_id
160	             WHERE ur.user_id = ?"
161	        )
162	        .bind(user_id)
163	        .fetch_all(&self.pool)
164	        .await?;
165	
166	        let permission_codes: HashSet<String> = perm_rows.into_iter().map(|r| r.0).collect();
167	
168	        // Load data scopes
169	        let scope_rows: Vec<DataScopeRow> = sqlx::query_as(
170	            "SELECT org_id, department_id, project_id, access_level
171	             FROM user_data_scopes WHERE user_id = ?"
172	        )
173	        .bind(user_id)
174	        .fetch_all(&self.pool)
175	        .await?;
176	
177	        let data_scopes: Vec<DataScope> = scope_rows
178	            .into_iter()
179	            .map(|r| DataScope {
180	                org_id: r.org_id,
181	                department_id: r.department_id,
182	                project_id: r.project_id,
183	                access_level: r.access_level,
184	            })
185	            .collect();
186	
187	        Ok(CachedUserPermissions {
188	            user_id: user_id.to_string(),
189	            permission_codes,
190	            data_scopes,
191	            role_names,
192	            cached_at: Instant::now(),
193	        })
194	    }
195	
196	    /// Check if a user has a specific permission code.
197	    pub async fn has_permission(&self, user_id: &str, permission_code: &str) -> Result<bool, sqlx::Error> {
198	        let perms = self.get_permissions(user_id).await?;
199	        // System Administrator has implicit all-access
200	        if perms.role_names.contains("System Administrator") {
201	            return Ok(true);
202	        }
203	        Ok(perms.permission_codes.contains(permission_code))
204	    }
205	
206	    /// Check if a user has data access to a specific org/department/project
207	    /// at the required access level.
208	    pub async fn check_data_scope(
209	        &self,
210	        user_id: &str,
211	        org_id: &str,
212	        department_id: Option<&str>,
213	        project_id: Option<&str>,
214	        required_level: &str,
215	    ) -> Result<bool, sqlx::Error> {
216	        let perms = self.get_permissions(user_id).await?;
217	
218	        // System Administrator bypasses scope checks
219	        if perms.role_names.contains("System Administrator") {
220	            return Ok(true);
221	        }
222	
223	        let level_rank = |level: &str| -> u8 {
224	            match level {
225	                "read" => 1,
226	                "write" => 2,
227	                "admin" => 3,
228	                _ => 0,
229	            }
230	        };
231	
232	        let required_rank = level_rank(required_level);
233	
234	        for scope in &perms.data_scopes {
235	            if scope.org_id != org_id {
236	                continue;
237	            }
238	            if level_rank(&scope.access_level) < required_rank {
239	                continue;
240	            }
241	            // Org-level scope grants access to all departments/projects within
242	            if scope.department_id.is_none() {
243	                return Ok(true);
244	            }
245	            // Department-level scope
246	            if let Some(dept) = department_id {
247	                if scope.department_id.as_deref() == Some(dept) {
248	                    // Department scope grants access to all projects within
249	                    if scope.project_id.is_none() {
250	                        return Ok(true);
251	                    }
252	                    // Project-level scope
253	                    if let Some(proj) = project_id {
254	                        if scope.project_id.as_deref() == Some(proj) {
255	                            return Ok(true);
256	                        }
257	                    }
258	                }
259	            }
260	        }
261	
262	        Ok(false)
263	    }
264	}
265	
266	#[derive(sqlx::FromRow)]
267	struct DataScopeRow {
268	    org_id: String,
269	    department_id: Option<String>,
270	    project_id: Option<String>,
271	    access_level: String,
272	}
