275	mod tests {
276	    use super::*;
277	
278	    #[test]
279	    fn test_data_scope_level_ranking() {
280	        // Verify the level ranking logic
281	        let level_rank = |level: &str| -> u8 {
282	            match level {
283	                "read" => 1,
284	                "write" => 2,
285	                "admin" => 3,
286	                _ => 0,
287	            }
288	        };
289	        assert!(level_rank("admin") > level_rank("write"));
290	        assert!(level_rank("write") > level_rank("read"));
291	        assert!(level_rank("read") > level_rank("unknown"));
292	    }
293	
294	    #[test]
295	    fn test_cached_permissions_contains() {
296	        let perms = CachedUserPermissions {
297	            user_id: "u1".to_string(),
298	            permission_codes: HashSet::from([
299	                "menu.dashboard".to_string(),
300	                "api.users.read".to_string(),
301	            ]),
302	            data_scopes: vec![],
303	            role_names: HashSet::from(["Operations Manager".to_string()]),
304	            cached_at: Instant::now(),
305	        };
306	        assert!(perms.permission_codes.contains("menu.dashboard"));
307	        assert!(!perms.permission_codes.contains("api.users.write"));
308	    }
309	}
