281	/// Round a score to the nearest interval (e.g. 0.5).
282	/// Examples:
283	///   round_to_interval(7.3, 0.5) = 7.5
284	///   round_to_interval(7.2, 0.5) = 7.0
285	///   round_to_interval(7.25, 0.5) = 7.5
286	pub fn round_to_interval(score: f64, interval: f64) -> f64 {
287	    if interval <= 0.0 {
288	        return score;
289	    }
290	    let rounded = (score / interval).round() * interval;
291	    // Avoid floating-point drift: round to 4 decimal places
292	    (rounded * 10000.0).round() / 10000.0
293	}
294	
295	/// Compute auto-score for an objective question.
296	/// Returns max_points if answer matches correct_answer (case-insensitive trim), else 0.
297	pub fn compute_auto_score(answer_text: &str, correct_answer: &str, max_points: f64) -> f64 {
298	    if answer_text.trim().to_lowercase() == correct_answer.trim().to_lowercase() {
299	        max_points
300	    } else {
301	        0.0
302	    }
303	}
304	
305	/// Compute the final score for a single answer:
306	///   final = min(auto_score + manual_score + partial_credit_fraction * max_points, max_points)
307	pub fn compute_answer_final_score(
308	    auto_score: f64,
309	    manual_score: f64,
310	    partial_credit_fraction: f64,
311	    max_points: f64,
312	) -> f64 {
313	    let raw = auto_score + manual_score + (partial_credit_fraction * max_points);
314	    raw.min(max_points).max(0.0)
315	}
316	
317	/// Compute weighted evaluation score (0–100 scale) from answers and their questions.
318	/// Questions are paired with their weights. Returns (raw_sum, weighted_score_0_to_100).
319	pub fn compute_weighted_score(
320	    answers: &[(f64, f64, f64)], // (answer_final_score, question_weight, question_max_points)
321	) -> (f64, f64) {
322	    if answers.is_empty() {
323	        return (0.0, 0.0);
324	    }
325	
326	    let raw_sum: f64 = answers.iter().map(|(s, _, _)| s).sum();
327	    let total_max: f64 = answers.iter().map(|(_, _, m)| m).sum();
328	    let total_weight: f64 = answers.iter().map(|(_, w, _)| w).sum();
329	
330	    if total_weight <= 0.0 || total_max <= 0.0 {
331	        return (raw_sum, 0.0);
332	    }
333	
334	    // Weighted score: each answer contributes (final_score / max_points) * weight
335	    let weighted_sum: f64 = answers
336	        .iter()
337	        .map(|(s, w, m)| {
338	            if *m > 0.0 { (s / m) * w } else { 0.0 }
339	        })
340	        .sum();
341	
342	    // Normalize to 0–100
343	    let weighted_pct = (weighted_sum / total_weight) * 100.0;
344	    (raw_sum, (weighted_pct * 100.0).round() / 100.0)
345	}
