459	/// Returns true if the score change from prior to new exceeds 10 points.
460	/// This is the backend-enforced second-review trigger.
461	pub fn requires_second_review(prior_score: Option<f64>, new_score: f64) -> bool {
462	    match prior_score {
463	        Some(prior) => (new_score - prior).abs() > 10.0,
464	        None => false, // First evaluation never requires second review
465	    }
466	}
