24	    let mut active_tab = use_signal(|| ReportTab::Kpi);
25	
26	    let can_read = auth.read().has_permission("api.reports.read");
27	    let can_export = auth.read().has_permission("action.reports.export");
28	    let can_unmasked = auth.read().has_permission("api.export.unmasked");
29	
30	    if auth.read().token.is_none() {
31	        return rsx! {
32	            div { class: "page-header",
33	                h1 { "Reports & Exports" }
34	                p { style: "color: var(--color-text-secondary);",
35	                    "Your session has expired. Please log in again."
36	                }
37	            }
38	        };
39	    }
40	
41	    if !can_read {
42	        return rsx! {
43	            div { class: "page-header",
44	                h1 { "Reports & Exports" }
45	                p { style: "color: var(--color-text-secondary);",
46	                    "You do not have permission to view reports."
47	                }
48	            }
49	        };
50	    }
51	
52	    rsx! {
53	        div {
54	            div { class: "page-header",
55	                h1 { "Reports & Exports" }
56	                p { "Operational, financial, and quality analytics derived from stored data. Exports are masked by default." }
57	            }
58	
59	            div { style: "display: flex; gap: 4px; border-bottom: 2px solid var(--color-border); margin-bottom: 24px; flex-wrap: wrap;",
60	                TabButton {
61	                    label: "KPI Summary",
62	                    active: *active_tab.read() == ReportTab::Kpi,
63	                    onclick: move |_| { *active_tab.write() = ReportTab::Kpi; }
64	                }
65	                TabButton {
66	                    label: "Order Volume",
67	                    active: *active_tab.read() == ReportTab::OrderVolume,
68	                    onclick: move |_| { *active_tab.write() = ReportTab::OrderVolume; }
69	                }
70	                TabButton {
71	                    label: "Revenue",
72	                    active: *active_tab.read() == ReportTab::Revenue,
73	                    onclick: move |_| { *active_tab.write() = ReportTab::Revenue; }
74	                }
75	                TabButton {
76	                    label: "Utilization",
77	                    active: *active_tab.read() == ReportTab::Utilization,
78	                    onclick: move |_| { *active_tab.write() = ReportTab::Utilization; }
79	                }
80	                if can_export {
81	                    TabButton {
82	                        label: "Export",
83	                        active: *active_tab.read() == ReportTab::Export,
84	                        onclick: move |_| { *active_tab.write() = ReportTab::Export; }
85	                    }
86	                }
87	            }
88	
89	            match *active_tab.read() {
90	                ReportTab::Kpi          => rsx! { KpiTab {} },
91	                ReportTab::OrderVolume  => rsx! { OrderVolumeTab {} },
92	                ReportTab::Revenue      => rsx! { RevenueTab {} },
