449	#[component]
450	fn ExportTab(can_unmasked: bool) -> Element {
451	    let auth = use_context::<Signal<AuthState>>();
452	    let mut export_type = use_signal(|| "deliveries".to_string());
453	    let mut from_date = use_signal(|| "".to_string());
454	    let mut to_date = use_signal(|| "".to_string());
455	    let mut unmasked = use_signal(|| false);
456	    let mut error_msg = use_signal(|| String::new());
457	    let mut success_msg = use_signal(|| String::new());
458	    let mut export_result = use_signal(|| None::<ExportResult>);
459	
460	    let on_export = {
461	        let export_type = export_type.clone();
462	        let from_date = from_date.clone();
463	        let to_date = to_date.clone();
464	        let unmasked = unmasked.clone();
465	        let mut error_msg = error_msg.clone();
466	        let mut success_msg = success_msg.clone();
467	        let mut export_result = export_result.clone();
468	        move |_| {
469	            let et = export_type.read().clone();
470	            let f = from_date.read().clone();
471	            let td = to_date.read().clone();
472	            let um = *unmasked.read();
473	            if f.is_empty() || td.is_empty() {
474	                *error_msg.write() = "From and To dates are required.".to_string();
475	                return;
476	            }
477	            let t = auth.read().token.clone();
478	            spawn(async move {
479	                let body = serde_json::json!({
480	                    "export_type": et,
481	                    "from_date": f,
482	                    "to_date": td,
483	                    "unmasked": um,
484	                });
485	                match ApiClient::post::<ExportResult, _>("/reports/export", &body, t.as_deref()).await {
486	                    Ok(result) => {
487	                        let count = result.row_count;
488	                        let masked_label = if result.masked { "masked" } else { "unmasked" };
489	                        *success_msg.write() = format!("Export complete: {} rows ({}). Log ID: {}", count, masked_label, &result.export_log_id[..8]);
490	                        *error_msg.write() = String::new();
491	                        *export_result.write() = Some(result);
492	                    }
493	                    Err(e) => {
494	                        *error_msg.write() = e;
495	                        *success_msg.write() = String::new();
496	                        *export_result.write() = None;
497	                    }
498	                }
499	            });
500	        }
501	    };
502	
503	    rsx! {
