312	            let row: (i64, i64) = sqlx::query_as(
313	                "SELECT
314	                    SUM(CASE WHEN de.status = 'submitted' THEN 1 ELSE 0 END),
315	                    SUM(CASE WHEN de.status = 'verified'  THEN 1 ELSE 0 END)
316	                 FROM delivery_entries de
317	                 JOIN client_plans cp ON cp.id = de.plan_id AND cp.org_id = ?
318	                 WHERE de.delivery_date BETWEEN ? AND ?"
319	            )
320	            .bind(org_id)
321	            .bind(&filters.from_date)
322	            .bind(&filters.to_date)
323	            .fetch_one(&self.pool)
324	            .await
325	            .map_err(|e| AppError::Internal(e.to_string()))?;
326	            row
327	        };
328	
329	        let attendance_rate_pct = {
330	            let total = submitted_count + verified_count;
331	            if total > 0 {
332	                (verified_count as f64 / total as f64) * 100.0
333	            } else {
334	                0.0
335	            }
336	        };
337	
338	        // 2. Repurchase rate: plans with 2+ invoice billing periods / total plans
339	        let (plans_with_repeat, total_plans): (i64, i64) = {
340	            let row: (i64, i64) = sqlx::query_as(
341	                "SELECT
342	                    SUM(CASE WHEN invoice_periods >= 2 THEN 1 ELSE 0 END),
343	                    COUNT(*)
344	                 FROM (
345	                    SELECT cp.id, COUNT(DISTINCT DATE_FORMAT(i.created_at, '%Y-%m')) AS invoice_periods
346	                    FROM client_plans cp
347	                    LEFT JOIN invoices i ON i.plan_id = cp.id
348	                        AND DATE(i.created_at) BETWEEN ? AND ?
349	                    WHERE cp.org_id = ?
350	                    GROUP BY cp.id
351	                 ) plan_periods"
352	            )
353	            .bind(&filters.from_date)
354	            .bind(&filters.to_date)
355	            .bind(org_id)
356	            .fetch_one(&self.pool)
357	            .await
358	            .map_err(|e| AppError::Internal(e.to_string()))?;
359	            row
360	        };
361	
362	        let repurchase_rate_pct = if total_plans > 0 {
363	            (plans_with_repeat as f64 / total_plans as f64) * 100.0
364	        } else {
365	            0.0
366	        };
367	
368	        // 3. Staff utilization: avg deliveries per active provider / 20 (capacity proxy per week)
369	        let (total_deliveries, provider_count): (i64, i64) = {
370	            let row: (i64, i64) = sqlx::query_as(
371	                "SELECT COUNT(de.id), COUNT(DISTINCT de.provider_id)
372	                 FROM delivery_entries de
373	                 JOIN client_plans cp ON cp.id = de.plan_id AND cp.org_id = ?
374	                 WHERE de.delivery_date BETWEEN ? AND ?"
375	            )
376	            .bind(org_id)
377	            .bind(&filters.from_date)
378	            .bind(&filters.to_date)
379	            .fetch_one(&self.pool)
380	            .await
381	            .map_err(|e| AppError::Internal(e.to_string()))?;
382	            row
383	        };
384	
385	        // Approximate weeks in range
386	        let weeks: f64 = {
387	            let from = chrono::NaiveDate::parse_from_str(&filters.from_date, "%Y-%m-%d")
388	                .unwrap_or_default();
389	            let to = chrono::NaiveDate::parse_from_str(&filters.to_date, "%Y-%m-%d")
390	                .unwrap_or_default();
391	            let days = (to - from).num_days().max(1) as f64;
392	            (days / 7.0).ceil()
393	        };
394	
395	        let staff_utilization_pct = if provider_count > 0 && weeks > 0.0 {
396	            let avg_per_provider_per_week = total_deliveries as f64 / provider_count as f64 / weeks;
397	            // Capacity proxy: 20 deliveries per week = 100%
398	            (avg_per_provider_per_week / 20.0 * 100.0).min(100.0)
399	        } else {
400	            0.0
401	        };
