use sqlx::{Executor, MySqlPool};
use std::str::FromStr;

pub async fn create_pool(database_url: &str) -> MySqlPool {
    tracing::info!("Connecting to database");

    // Parse the connection URL into options so we can configure the session.
    let options = MySqlConnectOptions::from_str(database_url)
        .expect("Invalid DATABASE_URL")
        .timezone(Some(String::from("+00:00")));

    // Use after_connect to set session variables on every new connection.
    // Setting time_zone = '+00:00' ensures MySQL TIMESTAMP columns are returned
    // without timezone conversion.  More importantly, setting sql_mode to
    // include NO_ZERO_DATE etc. keeps decoding deterministic.  This is applied
    // per-connection so every pooled connection sees UTC.
    MySqlPoolOptions::new()
        .max_connections(10)
        .after_connect(|conn, _meta| Box::pin(async move {
            conn.execute("SET time_zone = '+00:00'").await?;
            Ok(())
        }))
        .connect_with(options)
        .await
        .expect("Failed to connect to database")
}"}

