13	pub async fn run_migrations(pool: &MySqlPool) {
14	    tracing::info!("Running database migrations");
15	
16	    // Repair dirty migrations: if a previous run crashed mid-migration,
17	    // sqlx records success=0 and refuses to retry.  Delete the dirty
18	    // record so the (now-idempotent) migration file can be re-applied.
19	    let _ = sqlx::query(
20	        "DELETE FROM _sqlx_migrations WHERE success = 0"
21	    )
22	    .execute(pool)
23	    .await; // Ignore error — table may not exist on first run.
24	
25	    sqlx::migrate!("./migrations")
26	        .run(pool)
27	        .await
28	        .expect("Failed to run migrations");
29	    tracing::info!("Migrations completed");
30	}
